var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"……사장님.","JPN":"……社長。","ENG":"…Boss.","TWN":"……老闆。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"사장님은 저보다 저에 대해서 더 많은 것을 알고 계시죠?","JPN":"社長は私よりも私について知っていますよね？","ENG":"You seem to know more about me than I know myself.","TWN":"關於我的事，老闆知道的比我還多吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"그럼, 가르쳐 주실 수 있나요?","JPN":"では、教えていただけませんか？","ENG":"Will you teach me?","TWN":"可以請老闆告訴我嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"할아버님께서 하셨던 수많은 말씀 중에……","JPN":"お祖父様がおっしゃった数多くの言葉の中で……","ENG":"My grandfather said...","TWN":"爺爺說過的話之中……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"언젠가 <color=#ffd34c>있는 그대로의 절</color> 받아들여 줄 분이 나타날 거라던 그 말…….","JPN":"いつか<color=#ffd34c>私をありのまま</color>受け入れてくれる、たった一人の相手に巡り会えるという言葉……","ENG":"that one day I'd meet someone who would accept<color=#ffd34c> me as I am</color>...","TWN":"總有一天我會遇到一個欣賞<color=#ffd34c>我本來樣子</color>的人……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"그 말은 할아버님의 진심이었나요?","JPN":"お祖父様のあの言葉は本心だったのですか？","ENG":"Do you think he meant what he said?","TWN":"這句話，爺爺是認真的嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"……그 분은 역시 사장님이신가요?","JPN":"……たった一人の相手とは、やはり社長でしょうか？","ENG":"...And could that person... be you?","TWN":"……那個人就是老闆嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"역시 가르쳐 주지 않으시는군요, 사장님.","JPN":"やっぱり教えてくれないんですね、社長。","ENG":"I see you don’t want to say...","TWN":"我就知道你不會跟我說。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"후훗, 하지만 괜찮아요.","JPN":"フフッ、でも大丈夫です。","ENG":"Hah hah, it's okay.","TWN":"呵呵，不過沒關係！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"저는 이미 있는 그대로의 절 봐주시는 분을 찾았는 걸요?","JPN":"私はすでに、ありのままの私を受け入れてくれる方を見つけていますからね。","ENG":"I think I’ve already found that person.","TWN":"我已經找到那個欣賞我本來樣子的人！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"아주, 멋지고 친절하신 분이 이렇게 제 진짜 모습을 봐주시고 있으니까요.","JPN":"とても素敵で親切な方が、こうして私の本当の姿を見てくださっています。","ENG":"That kind and generous person is already seeing me for who I really am.","TWN":"他非常帥氣，是個很親切的人，而且在他眼裡看到的是真正的我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"그러니까, 믿을래요. 할아버님의 진심이 이루어졌다고.","JPN":"だから、信じます。お祖父様の願いが叶ったと。","ENG":"So, I want to believe... that what my grandfather said has come true.","TWN":"所以我相信，爺爺的話已經成真。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"고마워요, 사장님.","JPN":"ありがとうございます、社長。","ENG":"Thank you, sir.","TWN":"老闆，謝謝你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"제가 정말로 바라는 것을 찾을 수 있게 도와주셔서.","JPN":"私が本当の望みを見つけられるように手伝ってくださって。","ENG":"For helping me find what I’ve been searching for.","TWN":"謝謝老闆幫助我找到真正想要的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"……후훗, 그리고 앞으로도 잘 부탁드려요.","JPN":"……フフッ、これからもよろしくお願いします。","ENG":"...Hah hah. Also, I look forward to working with you.","TWN":"……呵呵～以後也請多多指教囉～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};